```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create deserializer object from the input buffer
    hexi::deserializer deserializer(buffer);

    NetworkPacket packet;

    // Read packet_id using read() function
    deserializer.read(&packet.packet_id);

    // Read username using prefixed adaptor
    deserializer.read(hexi::prefixed(packet.username));

    // Read score count, then use read_container to read scores vector
    uint32_t score_count;
    deserializer.read(&score_count);
    packet.scores.resize(score_count);
    deserializer.read_container(packet.scores);

    // Read metadata using null_terminated adaptor
    deserializer.read(hexi::null_terminated(packet.metadata));

    // Calculate padding and skip remaining bytes
    size_t padding = buffer.size() % 4;
    if (padding > 0) {
        deserializer.skip(4 - padding);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create deserializer object
    hexi::deserializer deserializer(buffer);

    PacketInfo info;

    // Use span() to get zero-copy view of packet_id
    auto packet_id_span = deserializer.span<uint32_t>(1);
    info.packet_id = packet_id_span[0];

    // Use prefixed adaptor to read username as string_view
    deserializer.read(hexi::prefixed(info.username));

    // Read score count and skip the scores data
    uint32_t score_count;
    deserializer.read(&score_count);
    deserializer.skip(score_count * sizeof(uint32_t));

    return info;
}
```

