```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Create a destination buffer to hold the previewed data
    std::vector<uint8_t> preview_buffer(bytes_to_preview);

    // Use the copy function to read data without advancing the read pointer
    // The copy function internally uses read_offset() to determine where to read from
    storage.copy(preview_buffer.data(), bytes_to_preview);

    return preview_buffer;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Calculate readable data size using write_offset() - read_offset()
    status.readable_size = storage.write_offset() - storage.read_offset();

    // Calculate free space using block_size() - write_offset()
    status.free_space = storage.block_size() - storage.write_offset();

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Use clear() function to reset both read and write offsets
    storage.clear();
}
```

