std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create file_buffer object
    hexi::file_buffer buffer(file_path);

    // Check if requested bytes are available
    if (bytes_to_read > buffer.size()) {
        throw std::runtime_error("Requested more bytes than available");
    }

    // Resize destination vector and read data
    std::vector<uint8_t> destination(bytes_to_read);
    buffer.read(destination.data(), bytes_to_read);

