```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>

template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, const std::vector<uint8_t>& data) {
    // Convert vector data to std::byte array and write to buffer
    if (!data.empty()) {
        buffer.write(reinterpret_cast<const std::byte*>(data.data()), data.size());
    }
}

template<size_t buffer_size = 1024>
std::vector<uint8_t> read_data_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_read) {
    // Create result vector and read data from buffer
    std::vector<uint8_t> result;
    result.reserve(bytes_to_read);

    if (bytes_to_read > 0) {
        std::byte temp[bytes_to_read];
        buffer.read(temp, bytes_to_read);

        // Convert read data to uint8_t
        result.resize(bytes_to_read);
        for (size_t i = 0; i < bytes_to_read; ++i) {
            result[i] = static_cast<uint8_t>(temp[i]);
        }
    }

    return result;
}
```

